class Node:
    def __init__(self, val=0, key=1000, next=None, prev=None):
        self.val = val
        self.key = key
        self.next = next
        self.prev = prev


class LRUCache:
    def __init__(self, capacity: int):
        self.head = Node()
        self.tail = self.head

        self.cache = {self.head.key: self.head}
        self.capacity:int = capacity
        self.items:int = 1

    def get(self, key: int) -> int:
        if key not in self.cache:
            return -1

        val:int = self.cache[key].val

        if self.cache[key].next:
            self.cache[key].next.prev = self.cache[key].prev
        else:
            return val

        if self.cache[key].prev:
            self.cache[key].prev.next = self.cache[key].next
        else:
            self.tail = self.cache[key].next


        node = Node(val, key)
        self.cache[key] = node

        self.head.next = node
        node.prev = self.head
        self.head = self.head.next

        return val


    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            self.cache[key].val = value
            return

        if self.capacity == self.items:
            self.tail = self.tail.next
            if self.tail.prev is not None:
                self.cache.pop(self.tail.prev.key, None)
                self.tail.prev = None
            self.items -= 1

        self.items += 1

        node = Node(value, key)

        self.head.next = node
        node.prev = self.head
        self.head = self.head.next

        self.cache[key] = node

